import React from "react"
import PropTypes from "prop-types"

const Project = ({
  url,
  name,
  createdAt,
  description,
  homepageUrl,
  primaryLanguage,
  openGraphImageUrl
}) => {
  return (
    <div className="w-3/12 bg-white m-2 rounded shadow-xl hover:shadow-inner">
      <a href={homepageUrl} target="_blank" rel="noopener noreferrer">
        <img className="rounded-t" src={openGraphImageUrl} alt={name} />
      </a>
      <div>{name}</div>
      <div>{createdAt}</div>
      <div>{description}</div>
      <a href={url}>Repo URL</a>
      <div>{primaryLanguage.name}</div>
    </div>
  )
}

Project.propTypes = {
  url: PropTypes.string.isRequired,
  name: PropTypes.string.isRequired,
  createdAt: PropTypes.string.isRequired,
  description: PropTypes.string.isRequired,
  homepageUrl: PropTypes.string.isRequired,
  openGraphImageUrl: PropTypes.string.isRequired,
  primaryLanguage: PropTypes.shape({
    name: PropTypes.string
  }).isRequired
}

export default Project
